if len(l) < 3:
        return False
    l.sort()
    for i in range(len(l) - 2):
        target = -l[i]
        left = i + 1
        right = len(l) - 1
        while left < right:
            curr_sum = l[left] + l[right]
            if curr_sum == target:
                return True
            elif curr_sum < target:
                left += 1
            else:
                right -= 1
    return False
